// ============================================
// Entity Types
// ============================================

export type UserRole = 'admin' | 'agent' | 'user';
export type TicketPriority = 'low' | 'medium' | 'high' | 'critical';
export type TicketStatus = 'open' | 'in_progress' | 'resolved' | 'closed' | 'cancelled';

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  createdAt: Date;
  updatedAt: Date;
}

export interface Ticket {
  id: string;
  title: string;
  description: string;
  priority: TicketPriority;
  status: TicketStatus;
  assignedTo: string | null;
  prLink: string | null;
  createdBy: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface Comment {
  id: string;
  ticketId: string;
  message: string;
  createdBy: string;
  createdAt: Date;
}

// ============================================
// API Request/Response Types
// ============================================

export interface CreateTicketDto {
  title: string;
  description: string;
  priority: TicketPriority;
  assignedTo?: string | null;
  prLink?: string | null;
  createdBy: string;
}

export interface UpdateTicketDto {
  title?: string;
  description?: string;
  priority?: TicketPriority;
  assignedTo?: string | null;
  prLink?: string | null;
}

export interface ChangeStatusDto {
  status: TicketStatus;
}

export interface CreateCommentDto {
  message: string;
  createdBy: string;
}

export interface TicketWithComments extends Ticket {
  comments: Comment[];
}

export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export interface TicketFilters {
  search?: string;
  status?: TicketStatus;
  priority?: TicketPriority;
  assignedTo?: string;
  page?: number;
  limit?: number;
}

// ============================================
// Error Types
// ============================================

export interface ApiError {
  message: string;
  field?: string;
  code?: string;
}

export interface ApiErrorResponse {
  errors: ApiError[];
}

import { TicketStatus } from './types';

/**
 * Valid state transitions for the ticket status state machine.
 * Key: current status → Value: array of valid next statuses.
 */
const VALID_TRANSITIONS: Record<TicketStatus, TicketStatus[]> = {
  open: ['in_progress', 'cancelled'],
  in_progress: ['resolved', 'cancelled'],
  resolved: ['closed'],
  closed: [],
  cancelled: [],
};

/**
 * Check if a status transition is valid according to the state machine rules.
 */
export function isValidTransition(
  currentStatus: TicketStatus,
  newStatus: TicketStatus,
): boolean {
  return VALID_TRANSITIONS[currentStatus].includes(newStatus);
}

/**
 * Get all valid next statuses for a given current status.
 */
export function getValidTransitions(currentStatus: TicketStatus): TicketStatus[] {
  return VALID_TRANSITIONS[currentStatus];
}

/**
 * Check if a status is a terminal state (no further transitions possible).
 */
export function isTerminalState(status: TicketStatus): boolean {
  return VALID_TRANSITIONS[status].length === 0;
}

import { Request, Response, NextFunction } from 'express';
import { ZodError, ZodSchema } from 'zod';

export function validate(schema: ZodSchema) {
  return (req: Request, res: Response, next: NextFunction): void => {
    try {
      req.body = schema.parse(req.body);
      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const errors = error.errors.map((err) => ({
          message: err.message,
          field: err.path.join('.'),
          code: err.code,
        }));
        res.status(422).json({ errors });
        return;
      }
      next(error);
    }
  };
}

import { Request, Response, NextFunction } from 'express';

export class AppError extends Error {
  constructor(
    public statusCode: number,
    public message: string,
    public errors: Array<{ message: string; field?: string; code?: string }> = [],
  ) {
    super(message);
    this.name = 'AppError';
    if (errors.length === 0) {
      this.errors = [{ message }];
    }
  }
}

export function errorHandler(
  err: Error,
  _req: Request,
  res: Response,
  _next: NextFunction,
): void {
  if (err instanceof AppError) {
    res.status(err.statusCode).json({ errors: err.errors });
    return;
  }

  console.error('Unhandled error:', err);
  res.status(500).json({
    errors: [{ message: 'Internal server error' }],
  });
}

import { pool } from '../config/database';
