    );
    return result.rows;
  }

  async findById(id: string): Promise<User | null> {
    const result = await pool.query(
      'SELECT id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt" FROM users WHERE id = $1',
      [id],
    );
    return result.rows[0] || null;
  }

  async findByEmail(email: string): Promise<User | null> {
    const result = await pool.query(
      'SELECT id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt" FROM users WHERE email = $1',
      [email],
    );
    return result.rows[0] || null;
  }
}

import { pool } from '../config/database';
import {
  Ticket,
  CreateTicketDto,
  UpdateTicketDto,
  TicketStatus,
  TicketFilters,
  PaginatedResponse,
} from '../models/types';

export class TicketRepository {
  async findAll(filters: TicketFilters): Promise<PaginatedResponse<Ticket>> {
    const page = filters.page || 1;
    const limit = filters.limit || 20;
    const offset = (page - 1) * limit;

    const conditions: string[] = [];
    const params: unknown[] = [];
    let paramIndex = 1;

    if (filters.status) {
      conditions.push(`t.status = $${paramIndex++}`);
      params.push(filters.status);
    }

    if (filters.priority) {
      conditions.push(`t.priority = $${paramIndex++}`);
      params.push(filters.priority);
    }

    if (filters.assignedTo) {
      conditions.push(`t.assigned_to = $${paramIndex++}`);
      params.push(filters.assignedTo);
    }

    if (filters.search) {
      conditions.push(
        `to_tsvector('english', t.title || ' ' || t.description) @@ plainto_tsquery('english', $${paramIndex++})`,
      );
      params.push(filters.search);
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    const countResult = await pool.query(
      `SELECT COUNT(*) FROM tickets t ${whereClause}`,
      params,
    );
    const total = parseInt(countResult.rows[0].count, 10);

    const dataParams = [...params, limit, offset];
    const result = await pool.query(
      `SELECT t.id, t.title, t.description, t.priority, t.status,
              t.assigned_to AS "assignedTo", t.pr_link AS "prLink",
              t.created_by AS "createdBy",
              t.created_at AS "createdAt", t.updated_at AS "updatedAt"
       FROM tickets t
       ${whereClause}
       ORDER BY t.created_at DESC
       LIMIT $${paramIndex++} OFFSET $${paramIndex++}`,
      dataParams,
    );

    return {
      data: result.rows,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    };
  }

  async findById(id: string): Promise<Ticket | null> {
    const result = await pool.query(
      `SELECT id, title, description, priority, status,
              assigned_to AS "assignedTo", pr_link AS "prLink",
              created_by AS "createdBy",
              created_at AS "createdAt", updated_at AS "updatedAt"
       FROM tickets WHERE id = $1`,
      [id],
    );
    return result.rows[0] || null;
  }

  async create(dto: CreateTicketDto): Promise<Ticket> {
    const result = await pool.query(
      `INSERT INTO tickets (title, description, priority, assigned_to, pr_link, created_by)
       VALUES ($1, $2, $3, $4, $5, $6)
       RETURNING id, title, description, priority, status,
                 assigned_to AS "assignedTo", pr_link AS "prLink",
                 created_by AS "createdBy",
                 created_at AS "createdAt", updated_at AS "updatedAt"`,
      [dto.title, dto.description, dto.priority, dto.assignedTo || null, dto.prLink || null, dto.createdBy],
    );
    return result.rows[0];
  }

  async update(id: string, dto: UpdateTicketDto): Promise<Ticket | null> {
    const setClauses: string[] = [];
    const params: unknown[] = [];
    let paramIndex = 1;

    if (dto.title !== undefined) {
      setClauses.push(`title = $${paramIndex++}`);
      params.push(dto.title);
    }
    if (dto.description !== undefined) {
      setClauses.push(`description = $${paramIndex++}`);
      params.push(dto.description);
    }
    if (dto.priority !== undefined) {
      setClauses.push(`priority = $${paramIndex++}`);
      params.push(dto.priority);
    }
    if (dto.assignedTo !== undefined) {
      setClauses.push(`assigned_to = $${paramIndex++}`);
      params.push(dto.assignedTo);
    }
    if (dto.prLink !== undefined) {
      setClauses.push(`pr_link = $${paramIndex++}`);
      params.push(dto.prLink);
    }

    if (setClauses.length === 0) return this.findById(id);

    params.push(id);
    const result = await pool.query(
      `UPDATE tickets SET ${setClauses.join(', ')}
       WHERE id = $${paramIndex}
       RETURNING id, title, description, priority, status,
                 assigned_to AS "assignedTo", pr_link AS "prLink",
                 created_by AS "createdBy",
                 created_at AS "createdAt", updated_at AS "updatedAt"`,
      params,
    );
    return result.rows[0] || null;
  }

  async updateStatus(id: string, status: TicketStatus): Promise<Ticket | null> {
    const result = await pool.query(
      `UPDATE tickets SET status = $1
       WHERE id = $2
       RETURNING id, title, description, priority, status,
                 assigned_to AS "assignedTo", pr_link AS "prLink",
                 created_by AS "createdBy",
                 created_at AS "createdAt", updated_at AS "updatedAt"`,
      [status, id],
    );
    return result.rows[0] || null;
  }

  async getStatusCounts(): Promise<Record<TicketStatus, number>> {
    const result = await pool.query(
      `SELECT status, COUNT(*)::int as count FROM tickets GROUP BY status`,
    );
    const counts: Record<string, number> = {
      open: 0,
      in_progress: 0,
      resolved: 0,
      closed: 0,
      cancelled: 0,
    };
    for (const row of result.rows) {
      counts[row.status] = row.count;
    }
    return counts as Record<TicketStatus, number>;
  }

  async getResolvedCountByPeriod(
    period: 'week' | 'month' | 'year',
  ): Promise<number> {
    const intervals: Record<string, string> = {
      week: '7 days',
      month: '30 days',
      year: '365 days',
    };
    const result = await pool.query(
      `SELECT COUNT(*)::int as count FROM tickets
       WHERE status IN ('resolved', 'closed')
       AND updated_at >= NOW() - INTERVAL '${intervals[period]}'`,
    );
    return result.rows[0].count;
  }
}

import { pool } from '../config/database';
import { Comment, CreateCommentDto } from '../models/types';

export class CommentRepository {
  async findByTicketId(ticketId: string): Promise<Comment[]> {
    const result = await pool.query(
      `SELECT id, ticket_id AS "ticketId", message,
              created_by AS "createdBy", created_at AS "createdAt"
       FROM comments
       WHERE ticket_id = $1
       ORDER BY created_at ASC`,
      [ticketId],
    );
    return result.rows;
  }

  async create(ticketId: string, dto: CreateCommentDto): Promise<Comment> {
    const result = await pool.query(
      `INSERT INTO comments (ticket_id, message, created_by)
       VALUES ($1, $2, $3)
       RETURNING id, ticket_id AS "ticketId", message,
                 created_by AS "createdBy", created_at AS "createdAt"`,
      [ticketId, dto.message, dto.createdBy],
    );
    return result.rows[0];
  }
}

import { UserRepository } from '../repositories/user.repository';
import { User } from '../models/types';
import { AppError } from '../middleware/error-handler';

export class UserService {
  private userRepository: UserRepository;

  constructor(userRepository?: UserRepository) {
    this.userRepository = userRepository || new UserRepository();
  }

  async getAllUsers(): Promise<User[]> {
    return this.userRepository.findAll();
  }

  async getUserById(id: string): Promise<User> {
    const user = await this.userRepository.findById(id);
    if (!user) {
      throw new AppError(404, 'User not found');
    }
    return user;
  }
}

import { TicketRepository } from '../repositories/ticket.repository';
import {
  Ticket,
  CreateTicketDto,
  UpdateTicketDto,
  TicketStatus,
  TicketFilters,
  PaginatedResponse,
} from '../models/types';
import { isValidTransition, getValidTransitions } from '../models/state-machine';
import { AppError } from '../middleware/error-handler';

export class TicketService {
  private ticketRepository: TicketRepository;

  constructor(ticketRepository?: TicketRepository) {
    this.ticketRepository = ticketRepository || new TicketRepository();
  }

  async getAllTickets(filters: TicketFilters): Promise<PaginatedResponse<Ticket>> {
    return this.ticketRepository.findAll(filters);
  }

  async getTicketById(id: string): Promise<Ticket> {
    const ticket = await this.ticketRepository.findById(id);
    if (!ticket) {
      throw new AppError(404, 'Ticket not found');
    }
    return ticket;
  }

  async createTicket(dto: CreateTicketDto): Promise<Ticket> {
    return this.ticketRepository.create(dto);
  }

  async updateTicket(id: string, dto: UpdateTicketDto): Promise<Ticket> {
    const existing = await this.ticketRepository.findById(id);
    if (!existing) {
      throw new AppError(404, 'Ticket not found');
    }
    const updated = await this.ticketRepository.update(id, dto);
    if (!updated) {
      throw new AppError(500, 'Failed to update ticket');
    }
    return updated;
  }

  async changeStatus(id: string, newStatus: TicketStatus): Promise<Ticket> {
    const ticket = await this.ticketRepository.findById(id);
    if (!ticket) {
      throw new AppError(404, 'Ticket not found');
    }

    if (!isValidTransition(ticket.status, newStatus)) {
      const validNext = getValidTransitions(ticket.status);
      const validStr = validNext.length > 0 ? validNext.join(', ') : 'none (terminal state)';
      throw new AppError(422, `Invalid status transition from '${ticket.status}' to '${newStatus}'. Valid transitions: ${validStr}`);
    }

    const updated = await this.ticketRepository.updateStatus(id, newStatus);
    if (!updated) {
      throw new AppError(500, 'Failed to update ticket status');
    }
    return updated;
  }

  async getStatusCounts(): Promise<Record<TicketStatus, number>> {
    return this.ticketRepository.getStatusCounts();
  }

  async getResolvedCountByPeriod(period: 'week' | 'month' | 'year'): Promise<number> {
    return this.ticketRepository.getResolvedCountByPeriod(period);
  }
}

import { CommentRepository } from '../repositories/comment.repository';
import { TicketRepository } from '../repositories/ticket.repository';
import { Comment, CreateCommentDto } from '../models/types';
import { AppError } from '../middleware/error-handler';

export class CommentService {
  private commentRepository: CommentRepository;
  private ticketRepository: TicketRepository;

  constructor(commentRepository?: CommentRepository, ticketRepository?: TicketRepository) {
    this.commentRepository = commentRepository || new CommentRepository();
    this.ticketRepository = ticketRepository || new TicketRepository();
  }

  async getCommentsByTicketId(ticketId: string): Promise<Comment[]> {
    const ticket = await this.ticketRepository.findById(ticketId);
    if (!ticket) {
      throw new AppError(404, 'Ticket not found');
    }
    return this.commentRepository.findByTicketId(ticketId);
  }

  async addComment(ticketId: string, dto: CreateCommentDto): Promise<Comment> {
    const ticket = await this.ticketRepository.findById(ticketId);
    if (!ticket) {
      throw new AppError(404, 'Ticket not found');
    }
    return this.commentRepository.create(ticketId, dto);
  }
}

