      expect(res.status).toBe(200);
      expect(res.body.data).toBeInstanceOf(Array);
      expect(res.body).toHaveProperty('total');
      expect(res.body).toHaveProperty('page');
      expect(res.body).toHaveProperty('totalPages');
    });

    it('filters by status', async () => {
      const res = await request(app).get('/api/tickets?status=open');
      expect(res.status).toBe(200);
      res.body.data.forEach((ticket: { status: string }) => {
        expect(ticket.status).toBe('open');
      });
    });

    it('searches by keyword', async () => {
      const res = await request(app).get('/api/tickets?search=Safari');
      expect(res.status).toBe(200);
      expect(res.body.data.length).toBeGreaterThan(0);
    });
  });

  describe('GET /api/tickets/:id', () => {
    it('returns ticket details (200)', async () => {
      const res = await request(app).get('/api/tickets/11111111-1111-1111-1111-111111111111');
      expect(res.status).toBe(200);
      expect(res.body.data).toHaveProperty('title');
      expect(res.body.data).toHaveProperty('status');
    });

    it('returns 404 for non-existent ticket', async () => {
      const res = await request(app).get('/api/tickets/00000000-0000-0000-0000-000000000000');
      expect(res.status).toBe(404);
    });
  });
});

