  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: var(--space-md);
  overflow-x: auto;
  padding-bottom: var(--space-md);
  min-height: 500px;
}

@media (max-width: 1200px) {
  .kanban-board {
    grid-template-columns: repeat(3, minmax(250px, 1fr));
  }
}

@media (max-width: 768px) {
  .kanban-board {
    grid-template-columns: repeat(2, minmax(220px, 1fr));
  }
}

