import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { User } from '../types';
import { ticketService } from '../services/ticket.service';
import { userService } from '../services/user.service';
import { Card, LoadingSpinner } from '../components/common';
import { TicketForm } from '../components/TicketForm';

// Default user for demo
const CURRENT_USER_ID = 'c3d4e5f6-a7b8-9012-cdef-123456789012';

export const CreateTicketPage: React.FC = () => {
  const navigate = useNavigate();
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    userService.getAll().then(setUsers).finally(() => setLoading(false));
  }, []);

  const handleSubmit = async (data: {
    title: string;
    description: string;
    priority: 'low' | 'medium' | 'high' | 'critical';
    assignedTo: string;
    prLink: string;
  }) => {
    setSubmitting(true);
    try {
      const ticket = await ticketService.create({
        ...data,
        assignedTo: data.assignedTo || null,
        prLink: data.prLink || null,
        createdBy: CURRENT_USER_ID,
      });
      navigate(`/tickets/${ticket.id}`);
    } catch {
      // Error handled by interceptor
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <LoadingSpinner message="Loading..." />;

  return (
    <div style={{ maxWidth: '700px', margin: '0 auto' }}>
      <h1 style={{ marginBottom: 'var(--space-lg)' }}>Create New Ticket</h1>
      <Card padding="lg">
        <TicketForm
          users={users}
          onSubmit={handleSubmit}
          onCancel={() => navigate(-1)}
          loading={submitting}
        />
      </Card>
    </div>
  );
};

import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Ticket, TicketStatus } from '../types';
import { ticketService } from '../services/ticket.service';
import { LoadingSpinner } from '../components/common';
import { KanbanBoard } from '../components/KanbanBoard';

export const KanbanPage: React.FC = () => {
  const navigate = useNavigate();
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchTickets = useCallback(async () => {
    try {
      const result = await ticketService.getAll({ limit: 100 });
      setTickets(result.data);
    } catch {
      setError('Failed to load tickets');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTickets();
  }, [fetchTickets]);

  const handleStatusChange = async (ticketId: string, newStatus: TicketStatus): Promise<boolean> => {
    try {
      const updated = await ticketService.changeStatus(ticketId, newStatus);
      setTickets((prev) =>
        prev.map((t) => (t.id === ticketId ? updated : t)),
      );
      return true;
    } catch (err: unknown) {
      const apiErr = err as { errors?: Array<{ message: string }> };
      setError(apiErr.errors?.[0]?.message || 'Invalid status transition');
      setTimeout(() => setError(''), 3000);
      return false;
    }
  };

  if (loading) return <LoadingSpinner message="Loading board..." />;

  return (
    <div>
      <h1 style={{ marginBottom: 'var(--space-lg)' }}>Kanban Board</h1>
      {error && (
        <div style={{
          padding: 'var(--space-sm) var(--space-md)',
          backgroundColor: '#fee2e2',
          color: '#991b1b',
          borderRadius: 'var(--radius-md)',
          marginBottom: 'var(--space-md)',
          fontSize: 'var(--font-size-sm)',
        }} role="alert">
          {error}
        </div>
      )}
      <KanbanBoard
        tickets={tickets}
        onStatusChange={handleStatusChange}
        onTicketClick={(ticketId) => navigate(`/tickets/${ticketId}`)}
      />
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Card, LoadingSpinner } from '../components/common';
import { ticketService } from '../services/ticket.service';
import { TicketStatus, STATUS_LABELS } from '../types';
import './DashboardPage.css';

export const DashboardPage: React.FC = () => {
  const [statusCounts, setStatusCounts] = useState<Record<TicketStatus, number> | null>(null);
  const [resolvedWeek, setResolvedWeek] = useState<number>(0);
  const [resolvedMonth, setResolvedMonth] = useState<number>(0);
  const [resolvedYear, setResolvedYear] = useState<number>(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [counts, week, month, year] = await Promise.all([
          ticketService.getStatusCounts(),
          ticketService.getResolvedByPeriod('week'),
          ticketService.getResolvedByPeriod('month'),
          ticketService.getResolvedByPeriod('year'),
        ]);
        setStatusCounts(counts);
        setResolvedWeek(week);
        setResolvedMonth(month);
        setResolvedYear(year);
      } catch {
        // Error handled
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) return <LoadingSpinner message="Loading dashboard..." />;

  const totalTickets = statusCounts
    ? Object.values(statusCounts).reduce((sum, c) => sum + c, 0)
    : 0;

  return (
    <div className="dashboard">
      <h1>Dashboard</h1>

      <section className="dashboard__section">
        <h2>Resolved Tickets</h2>
        <div className="dashboard__stats-grid">
          <Card padding="lg" className="dashboard__stat-card">
            <span className="dashboard__stat-value">{resolvedWeek}</span>
            <span className="dashboard__stat-label">Last 7 Days</span>
          </Card>
          <Card padding="lg" className="dashboard__stat-card">
            <span className="dashboard__stat-value">{resolvedMonth}</span>
            <span className="dashboard__stat-label">Last 30 Days</span>
          </Card>
          <Card padding="lg" className="dashboard__stat-card">
            <span className="dashboard__stat-value">{resolvedYear}</span>
            <span className="dashboard__stat-label">Last Year</span>
          </Card>
        </div>
      </section>

      <section className="dashboard__section">
        <h2>Tickets by Status</h2>
        <p className="dashboard__total">{totalTickets} total tickets</p>
        <div className="dashboard__status-grid">
          {statusCounts &&
            (Object.entries(statusCounts) as [TicketStatus, number][]).map(([status, count]) => (
              <Card key={status} padding="md" className="dashboard__status-card">
                <div
                  className="dashboard__status-indicator"
                  style={{ backgroundColor: `var(--color-status-${status.replace('_', '-')})` }}
                />
                <div className="dashboard__status-info">
                  <span className="dashboard__status-name">{STATUS_LABELS[status]}</span>
                  <span className="dashboard__status-count">{count}</span>
                </div>
                <div className="dashboard__status-bar">
                  <div
                    className="dashboard__status-bar-fill"
                    style={{
                      width: totalTickets > 0 ? `${(count / totalTickets) * 100}%` : '0%',
                      backgroundColor: `var(--color-status-${status.replace('_', '-')})`,
                    }}
                  />
                </div>
              </Card>
            ))}
        </div>
      </section>
    </div>
  );
};

